import React from 'react';
import { motion } from 'framer-motion';

const LoadingSpinner = ({ text = "Cargando..." }) => {
  const containerVariants = {
    start: {
      transition: {
        staggerChildren: 0.1,
      },
    },
    end: {
      transition: {
        staggerChildren: 0.1,
      },
    },
  };

  const circleVariants = {
    start: {
      y: "0%",
    },
    end: {
      y: "100%",
    },
  };

  const transition = {
    duration: 0.5,
    yoyo: Infinity,
    ease: "easeInOut",
  };

  return (
    <div className="flex flex-col items-center justify-center p-8">
      <motion.div
        className="flex justify-around w-16 h-8"
        variants={containerVariants}
        initial="start"
        animate="end"
      >
        <motion.span
          className="block w-4 h-4 bg-primary rounded-full"
          variants={circleVariants}
          transition={transition}
        />
        <motion.span
          className="block w-4 h-4 bg-accent rounded-full"
          variants={circleVariants}
          transition={transition}
        />
        <motion.span
          className="block w-4 h-4 bg-primary rounded-full"
          variants={circleVariants}
          transition={transition}
        />
      </motion.div>
      <p className="text-text-main mt-4">{text}</p>
    </div>
  );
};

export default LoadingSpinner;
